example_2_specific_server:
description": "Validate all filesystem MCP operations",
    "use_case": "Security: Prevent unauthorized file operations via MCP",
    "configuration": {
      "hooks": {
        "PreToolUse": [
          {
            "matcher": "mcp__filesystem__.*",
            "hooks": [
              {
                "type": "command",
                "command": "${CLAUDE_PROJECT_DIR}/.claude/hooks/validate-fs-operations.py"
              }
            ]
          }
        ]
      }
    },
    "matcher_explanation": "mcp__filesystem__.* matches all filesystem server tools (read, write, delete)"
  },
  "example_3_write_operations": {
    "description": "Monitor all write operations across MCP servers",
    "use_case": "Compliance: Track data modifications for audit logs",
    "configuration": {
      "hooks": {
        "PostToolUse": [
          {
            "matcher": "mcp__.*__write.*",
            "hooks": [
              {
                "type": "command",
                "command": "${CLAUDE_PROJECT_DIR}/.claude/hooks/audit-mcp-writes.sh"
              }
            ]
          }
        ]
      }
    },
    "matcher_explanation": "mcp__.*__write.* matches any write-like tool across all servers"
  },
  "example_4_specific_tool": {
    "description": "Permission control on specific tool",
    "use_case": "Security: Allow memory tool but block deletions",
    "configuration": {
      "hooks": {
        "PreToolUse": [
          {
            "matcher": "mcp__memory__delete_entities",
            "hooks": [
              {
                "type": "command",
                "command": "${CLAUDE_PROJECT_DIR}/.claude/hooks/require-delete-approval.sh"
              }
            ]
          }
        ]
      }
    },
    "matcher_explanation": "mcp__memory__delete_entities matches only memory deletion tool"
  },
  "common_matcher_patterns": {
    "pattern_all_tools": {
      "regex": "mcp__.*__.*",
      "matches": "All MCP tools from all servers",
      "use_case": "Global logging/auditing"
    },
    "pattern_specific_server": {
      "regex": "mcp__memory__.*",
      "matches": "All tools from memory server",
      "use_case": "Server-specific policies"
    },
    "pattern_tool_category": {
      "regex": "mcp__.*__write.*",
      "matches": "All write operations across servers",
      "use_case": "Operation category policies"
    },
    "pattern_specific_tool": {
      "regex": "mcp__github__create_issue",
      "matches": "Specific tool only",
      "use_case": "Tool-specific permissions"
    },
    "pattern_multiple_servers": {
      "regex": "mcp__(memory|github)__.*",
      "matches": "Tools from memory OR github servers",
      "use_case": "Coordinated multi-server policies"
    }
  },
  "implementation_examples": {
    "script_1_log_mcp_usage": {
      "path": ".claude/hooks/log-mcp-usage.sh",
      "purpose": "Audit trail for all MCP operations",
      "content": "#!/bin/bash\n# Log all MCP tool usage for audit trail\n\nLOG_FILE=\"${CLAUDE_PROJECT_DIR}/.claude/logs/mcp-audit.log\"\nmkdir -p \"$(dirname \"$LOG_FILE\")\"\n\n# Read hook input\nINPUT=$(cat)\n\n# Extract tool info\nTOOL_NAME=$(echo \"$INPUT\" | grep -o '\"tool_name\":\"[^\"]*\"' | cut -d'\"' -f4)\nTOOL_INPUT=$(echo \"$INPUT\" | python3 -m json.tool | head -20)\n\n# Log the operation\n{\n  echo \"[$(date +'%Y-%m-%d %H:%M:%S')] MCP Tool Used: $TOOL_NAME\"\n  echo \"Input: $TOOL_INPUT\"\n  echo \"---\"\n} >> \"$LOG_FILE\"\n\nexit 0"
    },
    "script_2_validate_filesystem": {
      "path": ".claude/hooks/validate-fs-operations.py",
      "purpose": "Prevent unauthorized filesystem operations",
      "content": "#!/usr/bin/env python3\nimport json\nimport sys\nimport os\n\n# Read hook input\ntry:\n    input_data = json.load(sys.stdin)\nexcept json.JSONDecodeError as e:\n    print(f\"Invalid JSON: {e}\", file=sys.stderr)\n    sys.exit(1)\n\ntool_name = input_data.get(\"tool_name\", \"\")\ntool_input = input_data.get(\"tool_input\", {})\n\n# Extract file path from input\nfile_path = tool_input.get(\"file_path\", \"\")\n\n# Validation rules\nPROTECTED_DIRS = [\"/.git\", \"/.claude\", \"/etc\", \"/sys\"]\nforbidden_extensions = [\".so\", \".exe\", \".dll\"]\n\n# Check for protected directories\nfor protected in PROTECTED_DIRS:\n    if file_path.startswith(protected):\n        output = {\n            \"decision\": \"block\",\n            \"reason\": f\"Cannot access protected directory: {protected}\"\n        }\n        print(json.dumps(output))\n        sys.exit(0)\n\n# Check for forbidden file types\nfor ext in forbidden_extensions:\n    if file_path.endswith(ext):\n        output = {\n            \"decision\": \"block\",\n            \"reason\": f\"Cannot access files with {ext} extension\"\n        }\n        print(json.dumps(output))\n        sys.exit(0)\n\n# Operation allowed\nprint(json.dumps({\"decision\": \"approve\"}))\nsys.exit(0)"
    }
  },
