  "real_world_scenarios": {
    "scenario_1_github_integration": {
      "description": "Company policy: Allow GitHub queries, block issue creation without review",
      "hooks": [
        {"matcher": "mcp__github__search_repositories", "type": "allow"},
        {"matcher": "mcp__github__create_issue", "type": "require_approval"},
        {"matcher": "mcp__github__delete_.*", "type": "block"}
      ]
    },
    "scenario_2_memory_audittrail": {
      "description": "Compliance requirement: Log all memory operations for retention",
      "hooks": [
        {"matcher": "mcp__memory__.*", "event": "PostToolUse", "action": "audit_log"}
      ]
    },
    "scenario_3_filesystem_protection": {
      "description": "Security: Prevent MCP filesystem tool from accessing sensitive directories",
      "hooks": [
        {"matcher": "mcp__filesystem__.*", "event": "PreToolUse", "action": "validate_path"}
      ]
    }
  }
}
